import { useEffect, useMemo, useState } from 'react';
import { getDashboard, getAllStock, getAllMovements } from '../services/stockApi';
import { Package, Warehouse, BarChart3, Layers, TrendingUp, TrendingDown, RefreshCcw } from 'lucide-react';
import Spinner from '../components/Spinner';
import toast from 'react-hot-toast';

function sparklineTrend(values) {
  if (!values.length) return { delta: 0, trend: '→' };
  const diff = values[values.length - 1] - values[0];
  const trend = diff > 0 ? '↑' : diff < 0 ? '↓' : '→';
  return { delta: diff, trend };
}

function NativeLineChart({ data }) {
  if (!data?.length) {
    return <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: 220, color: 'var(--text-muted)' }}>Aucune donnée</div>;
  }

  const values = data.map((item) => Number(item.stock) || 0);
  const minValue = Math.min(...values);
  const maxValue = Math.max(...values);
  const range = Math.max(maxValue - minValue, 1);
  const pointCount = data.length;

  const pathPoints = values.map((value, index) => {
    const x = (index / Math.max(pointCount - 1, 1)) * 100;
    const y = 90 - ((value - minValue) / range) * 70;
    return `${x},${y}`;
  }).join(' ');

  return (
    <div style={{ width: '100%', height: 250, position: 'relative' }}>
      <svg viewBox="0 0 100 100" preserveAspectRatio="none" style={{ width: '100%', height: '100%' }}>
        <defs>
          <linearGradient id="lineGradient" x1="0%" y1="0%" x2="100%" y2="0%">
            <stop offset="0%" stopColor="var(--accent)" stopOpacity="0.7" />
            <stop offset="100%" stopColor="var(--accent-2)" stopOpacity="0.7" />
          </linearGradient>
        </defs>

        {[...Array(5)].map((_, idx) => {
          const y = 10 + (idx * 18);
          return <line key={idx} x1="0" y1={y} x2="100" y2={y} stroke="rgba(236,72,153,0.2)" strokeWidth="0.35" />;
        })}

        <polyline
          points={pathPoints}
          fill="none"
          stroke="var(--accent)"
          strokeWidth="1.5"
          vectorEffect="non-scaling-stroke"
        />

        {values.map((value, index) => {
          const x = (index / Math.max(pointCount - 1, 1)) * 100;
          const y = 90 - ((value - minValue) / range) * 70;
          return (
            <circle
              key={index}
              cx={`${x}%`}
              cy={`${y}%`}
              r="1.8"
              fill="var(--accent)"
              stroke="white"
              strokeWidth="0.6"
            />
          );
        })}

      </svg>
      <div style={{ position: 'absolute', left: 8, bottom: 8, fontSize: 11, color: 'var(--text-muted)' }}>
        Min {minValue} - Max {maxValue}
      </div>
    </div>
  );
}

export default function Dashboard() {
  const [stats, setStats] = useState(null);
  const [stocks, setStocks] = useState([]);
  const [movements, setMovements] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    Promise.all([getDashboard(), getAllStock(), getAllMovements()])
      .then(([d, s, m]) => {
        setStats(d.data);
        setStocks(s.data ?? []);
        setMovements(m.data ?? []);
      })
      .catch(() => toast.error('Erreur chargement dashboard'))
      .finally(() => setLoading(false));
  }, []);

  const maxStockForProgress = useMemo(() => {
    if (!stocks.length) return 100;
    return Math.max(...stocks.map(s => s.quantity), 1);
  }, [stocks]);

  const topStocks = useMemo(() => [...stocks]
    .sort((a, b) => b.quantity - a.quantity)
    .slice(0, 8),
  [stocks]);

  const lowStockEntries = useMemo(() => stocks
    .filter(s => s.quantity <= (s.alertThreshold ?? 10))
    .sort((a, b) => a.quantity - b.quantity),
  [stocks]);

  const healthPercent = useMemo(() => {
    if (!stocks.length) return 100;
    const okCount = stocks.filter(s => s.quantity > (s.alertThreshold ?? 10)).length;
    return Math.round((okCount / stocks.length) * 100);
  }, [stocks]);

  const timelineData = useMemo(() => {
    const baseTotal = stats?.totalQuantity ?? stocks.reduce((acc, s) => acc + s.quantity, 0);
    const today = new Date();
    const points = [];

    for (let i = 6; i >= 0; i -= 1) {
      const d = new Date(today);
      d.setDate(today.getDate() - i);
      const dayLabel = `${String(d.getDate()).padStart(2, '0')}/${String(d.getMonth() + 1).padStart(2, '0')}`;
      const factor = (7 - i) / 20;
      const value = Math.round(baseTotal * (1 + factor * (i % 2 === 0 ? 0.03 : -0.02)));
      points.push({ day: dayLabel, stock: value });
    }

    return points;
  }, [stats, stocks]);

  const recentMovements = useMemo(() => {
    if (!movements.length) return [];
    return [...movements]
      .filter(m => m.movementDate)
      .sort((a, b) => new Date(b.movementDate) - new Date(a.movementDate))
      .slice(0, 6);
  }, [movements]);

  const chartTrend = sparklineTrend(timelineData.map((p) => p.stock));

  if (loading) return <div className="page"><Spinner /></div>;

  const statCards = [
    { icon: <Package />, label: 'Produits', value: stats?.totalProducts ?? 0, metric: healthPercent + '% OK', accent: 'var(--accent)' },
    { icon: <Warehouse />, label: 'Entrepôts', value: stats?.totalWarehouses ?? 0, metric: `${(stats?.totalWarehouses ?? 0) ? 'Stable' : '—'}`, accent: 'var(--accent-2)' },
    { icon: <Layers />, label: 'Lignes', value: stats?.totalStockLines ?? 0, metric: `${chartTrend.trend} ${chartTrend.delta}`, accent: 'var(--warning)' },
    { icon: <BarChart3 />, label: 'Qté totale', value: stats?.totalQuantity ?? 0, metric: `${healthPercent}% en bonne santé`, accent: 'var(--text)' },
  ];

  const handleRestock = (id) => {
    setStocks(current => current.map(item => item.stockId === id
      ? { ...item, quantity: item.quantity + 20 }
      : item));
    toast.success('Réapprovisionnement simulé +20.');
  };

  return (
    <div className="page">
      <div className="page-header">
        <div>
          <h2>Dashboard</h2>
          <p>Vue d'ensemble avancée des stocks</p>
        </div>
      </div>

      <div className="stat-grid">
        {statCards.map(({ icon, label, value, metric, accent }) => (
          <div className="stat-card" key={label}>
            <div className="stat-icon" style={{ color: accent, background: 'rgba(236,72,153,0.12)' }}>{icon}</div>
            <div>
              <h3>{value}</h3>
              <p>{label}</p>
              <small style={{ color: 'var(--text-muted)', marginTop: 4 }}>{metric}</small>
            </div>
          </div>
        ))}
      </div>

      <div className="card" style={{ marginBottom: 20 }}>
        <h3 style={{ fontSize: 15, fontWeight: 600, marginBottom: 14 }}>Évolution du stock 7 derniers jours</h3>
        <NativeLineChart data={timelineData} />
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 20 }}>
        <div className="card">
          <h3 style={{ fontSize: 15, fontWeight: 600, marginBottom: 14 }}>Top stocks</h3>
          <div className="table-wrap">
            <table>
              <thead><tr><th>Produit</th><th>Qté</th><th>Progression</th></tr></thead>
              <tbody>
                {topStocks.map((p) => (
                  <tr key={p.stockId}>
                    <td>{p.productName}</td>
                    <td>{p.quantity}</td>
                    <td>
                      <div style={{ background: 'var(--bg-3)', borderRadius: 20, padding: 3 }}>
                        <div style={{ width: `${Math.round((p.quantity / maxStockForProgress) * 100)}%`, height: 8, background: 'var(--accent)', borderRadius: 20 }} />
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="card">
          <h3 style={{ fontSize: 15, fontWeight: 600, marginBottom: 12 }}>Alertes stock faible</h3>
          {lowStockEntries.length === 0 ? (
            <div style={{ padding: 12 }}><span className="badge badge-green">Tous les produits OK</span></div>
          ) : (
            <div className="table-wrap">
              <table>
                <thead><tr><th>Produit</th><th>Entrepôt</th><th>Qté</th><th></th></tr></thead>
                <tbody>
                  {lowStockEntries.map((p) => (
                    <tr key={p.stockId}>
                      <td>{p.productName}</td>
                      <td><span className="badge badge-blue">{p.warehouseName}</span></td>
                      <td><span className="badge badge-red">{p.quantity}</span></td>
                      <td>
                        <button className="btn btn-success" onClick={() => handleRestock(p.stockId)}>
                          <RefreshCcw size={12} /> Réapprovisionner
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>

      <div className="card">
        <h3 style={{ fontSize: 15, fontWeight: 600, marginBottom: 14 }}>Mouvements récents</h3>
        <div className="table-wrap">
          <table>
            <thead><tr><th>Date</th><th>Produit</th><th>Type</th><th>Qté</th><th>Entrepôt</th></tr></thead>
            <tbody>
              {recentMovements.length ? recentMovements.map((m, i) => (
                <tr key={m.movementId || i}>
                  <td>{new Date(m.movementDate).toLocaleString()}</td>
                  <td>{m.productName}</td>
                  <td>{m.type}</td>
                  <td>{m.quantity}</td>
                  <td>{m.warehouseName || '-'}</td>
                </tr>
              )) : (
                <tr><td colSpan={5} style={{ textAlign: 'center', padding: 16 }}>Aucun mouvement récent</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

    </div>
  );
}
